+            }
+        }
+        if self.borders.contains(Borders::RIGHT) {
+            let x = area.right() - 1;
+            for y in area.y..area.bottom() {
+                buf.set(x, y, self.border_cell(set.vertical));
+            }
+        }
+        if self.borders.contains(Borders::TOP) {
+            for x in area.x..area.right() {
